class Solution:
    def validSquare(self, p1, p2, p3, p4):
        import itertools
        pts = [p1, p2, p3, p4]
        def d2(a, b):
            return (a[0] - b[0]) ** 2 + (a[1] - b[1]) ** 2
        for perm in itertools.permutations(pts):
            a, b, c, d = perm
            s = d2(a, b)
            if s == 0:
                continue
            if d2(b, c) == s and d2(c, d) == s and d2(d, a) == s and d2(a, c) == d2(b, d) and d2(a, c) == 2 * s:
                return True
        return False

