class Solution:
    def validSquare(self, p1, p2, p3, p4):
        pts = [p1, p2, p3, p4]
        dists = []
        for i in range(4):
            for j in range(i + 1, 4):
                dists.append((pts[i][0] - pts[j][0]) ** 2 + (pts[i][1] - pts[j][1]) ** 2)
        s = set(dists)
        if 0 in s:
            return False
        if len(s) != 2:
            return False
        small, big = min(s), max(s)
        return big == 2 * small

